/**
 * Generates src/index.server.ts re-exporting every generated *.server.ts
 * wrapper. The Stencil React Output Target only emits per-component server
 * files when `esModules` is enabled, so the barrel is created here at build
 * time to stay in sync with the components generated by the core build.
 */
import { existsSync, readdirSync, writeFileSync } from 'node:fs'
import { dirname, join } from 'node:path'
import { fileURLToPath } from 'node:url'

const packageDir = join(dirname(fileURLToPath(import.meta.url)), '..')
const componentsDir = join(packageDir, 'src', 'components')

if (!existsSync(componentsDir)) {
  console.error(
    `Components directory not found: ${componentsDir}\n` +
      'Run the core build first so the React Output Target generates the component wrappers.'
  )
  process.exit(1)
}

// Assumes every generated file follows the `atom-*` tag naming convention,
// matching the PascalCase export names of the client wrappers
// (e.g. atom-list-slider.server.ts -> AtomListSlider).
const toPascalCase = (tag) =>
  tag
    .split('-')
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
    .join('')

const serverFiles = readdirSync(componentsDir)
  .filter((file) => file.endsWith('.server.ts'))
  .sort((a, b) => a.localeCompare(b))

if (serverFiles.length === 0) {
  console.warn(
    'No *.server.ts wrappers found. Check that `hydrateModule` is configured ' +
      'in the React Output Target of packages/core/stencil.config.ts.'
  )
}

const exportLines = serverFiles.map((file) => {
  const tag = file.slice(0, file.length - '.server.ts'.length)

  return `export { ${toPascalCase(tag)} } from './components/${tag}.server.js'`
})

const content = [
  '/**',
  ' * This file is generated by scripts/generate-server-barrel.mjs.',
  ' * Server-side entry point for React SSR (Next.js).',
  ' */',
  ...exportLines,
  '',
].join('\n')

writeFileSync(join(packageDir, 'src', 'index.server.ts'), content)

console.log(`index.server.ts generated with ${serverFiles.length} components`)
